return [{ json: {
  resumen: `${ok} de ${total} leads enviados al Flujo 3`,
  exitosos: ok,
  fallidos: fail,
  instrucciones: 'Revisa HubSpot > Ventas > Negocios para ver los 10 deals en el pipeline como Nuevo Contacto'
} }];
